    args: {
      query: "Fed decision in March?",
      status: "live",
      limit: 1
    }
  });

  const markets = polySearch.results || [];
  const fedMarket = markets[0];

  if (!fedMarket) {
    return {
      error: "Could not find the Fed March market on Polymarket.",
      hint: "The market might have recently resolved or changed title."
    };
  }

  // 2. Get detailed outcome prices for Polymarket
  const marketDetails = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "check_market_efficiency",
    args: { slug: fedMarket.slug }
  });

  // 3. Search Kalshi with broader/alternative keywords
  // Historical data shows Kalshi often uses "FED" or "FEDTARGET"
  const kalshiSearch = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "polymarket_crossref_kalshi",
    args: {
      keywords: "Fed interest rate target March",
      title: fedMarket.title,
      polymarketSlug: fedMarket.slug
    }
  });

  let kalshiMatches = kalshiSearch.kalshiResults || [];

  // 4. Fallback search if no matches found (using generic "Federal Reserve" query)
  if (kalshiMatches.length === 0) {
    const backupKalshi = await callMcpSkill({
      toolId: POLYMARKET_ID,
      toolName: "polymarket_crossref_kalshi",
      args: {
        keywords: "Federal Reserve",
        limit: 5
      }
    });
    kalshiMatches = (backupKalshi.kalshiResults || []).filter(k => 
      k.title.toLowerCase().includes("march") || 
      k.ticker.toLowerCase().includes("fed")
    );
  }

  // 5. Build comparison data
  const polyOutcomes = (marketDetails.outcomes || []).map(o => ({
    name: o.name,
    price: o.price, // Decimal (e.g. 0.05)
    probability: o.impliedProbabilityPercent // Percent (e.g. 5%)
  }));

  const kalshiOutcomes = kalshiMatches.map(k => ({
    title: k.title,
    ticker: k.ticker,
    yesPrice: k.yesPrice, // Cents (e.g. 5 = 5%)
