  }

  return {
    polymarket: {
      title: fedMarket.title,
      url: fedMarket.url,
      outcomes: polyOutcomes
    },
    kalshi: kalshiOutcomes,
    analysis: {
      comparison,
      note: "Polymarket prices are decimals (0.01 = 1%); Kalshi prices are cents (1 = 1%)."
    }
  };
