  const POLYMARKET_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

  // 1. Search for a relevant Polymarket market first to get the slug and keywords
  const polySearch = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "search_markets",
    args: {
      query: "Fed interest rate meeting",
      limit: 5,
      status: "live"
    }
  });

  const markets = polySearch.results || [];
  // Find the most relevant "Fed meeting" market
  const fedMarket = markets.find(m => 
    m.title.toLowerCase().includes("fed") && 
    (m.title.toLowerCase().includes("rate") || m.title.toLowerCase().includes("interest"))
  );

  if (!fedMarket) {
    return {
      error: "Could not find an active Fed meeting market on Polymarket.",
      searchResults: markets
    };
  }

  // 2. Get detailed outcomes for this specific Polymarket event
  const polyOutcomes = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "get_event_outcomes",
    args: { slug: fedMarket.slug }
  });

  // 3. Cross-reference with Kalshi using keywords from the Polymarket title
  const crossRef = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "polymarket_crossref_kalshi",
    args: {
      keywords: "Federal Reserve interest rate hike cut",
      title: fedMarket.title,
      polymarketSlug: fedMarket.slug
    }
  });

  return {
    polymarket: {
      title: polyOutcomes.eventTitle,
      url: polyOutcomes.url,
      outcomes: polyOutcomes.outcomes.map(o => ({
        name: o.name,
        price: o.price,
        probability: o.pricePercent
      }))
    },
    kalshiMatches: crossRef.kalshiResults || [],
    note: "Compare the specific outcome brackets (e.g., 25bps vs 50bps) and dates between the two platforms to ensure a 1:1 comparison. Kalshi prices are in cents (e.g., 90 = 90%)."
  };
}

